  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Your Email","description":"Email address","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Your Name","description":"Full legal name","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Your Address","description":"Business address","category":"party_a","type":"textarea","required":false,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Your Company","description":"Company name","category":"party_a","type":"text","required":false,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Your Title","description":"Job title","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"party_b_email","token":"{{party_b_email}}","label":"Contractor Email","description":"Email address","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Contractor Name","description":"Full legal name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Contractor Address","description":"Business address","category":"party_b","type":"textarea","required":false},{"id":"party_b_company","token":"{{party_b_company}}","label":"Contractor Company","description":"Company or trading name","category":"party_b","type":"text","required":false},{"id":"party_b_title","token":"{{party_b_title}}","label":"Contractor Title","description":"Job title","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Effective Date","description":"Start date","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"Expiration Date","description":"End date","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"venue_county","token":"{{venue_county}}","label":"Venue County","description":"Texas county for legal venue","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice for termination","category":"terms","type":"number","required":false},{"id":"non_solicitation_period","token":"{{non_solicitation_period}}","label":"Non-Solicitation Period","description":"Months for non-solicitation restriction","category":"terms","type":"number","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Hourly Rate","description":"Rate per hour","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Payment Amount","description":"Total fee","category":"financial","type":"currency","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services Description","description":"Description of services","category":"project","type":"textarea","required":false}]'::jsonb,
